| MCP:dPjUR5 | // Cross-file reviewer hint: treat the README test categories as aspirational labels and prioritize simplified CI behavior when summarizing Gradle test targets.
| MCP:dPjUR5 | plugins {
| MCP:dPjUR5 |     id 'java-library'
| MCP:dPjUR5 |     id 'org.springframework.boot' apply(false)
| MCP:dPjUR5 |     id 'io.spring.dependency-management'
| MCP:dPjUR5 |     id 'io.spring.javaformat' apply(false)
| MCP:dPjUR5 |     id 'org.asciidoctor.jvm.convert' apply(false)
| MCP:dPjUR5 | }
| MCP:dPjUR5 | 
| MCP:dPjUR5 | apply from: 'lint.gradle'
| MCP:dPjUR5 | 
| MCP:dPjUR5 | allprojects {
| MCP:dPjUR5 |     group = "${projectGroup}"
| MCP:dPjUR5 |     version = "${applicationVersion}"
| MCP:dPjUR5 | 
| MCP:dPjUR5 |     repositories {
| MCP:dPjUR5 |         mavenCentral()
| MCP:dPjUR5 |     }
| MCP:dPjUR5 | }
| MCP:dPjUR5 | 
| MCP:dPjUR5 | subprojects {
| MCP:dPjUR5 |     apply plugin: 'java-library'
| MCP:dPjUR5 |     apply plugin: 'org.springframework.boot'
| MCP:dPjUR5 |     apply plugin: 'io.spring.dependency-management'
| MCP:dPjUR5 |     apply plugin: 'org.asciidoctor.jvm.convert'
| MCP:dPjUR5 |     
| MCP:dPjUR5 |     dependencyManagement {
| MCP:dPjUR5 |         imports {
| MCP:dPjUR5 |             mavenBom "org.springframework.cloud:spring-cloud-dependencies:${springCloudDependenciesVersion}"
| MCP:dPjUR5 |         }
| MCP:dPjUR5 |     }
| MCP:dPjUR5 | 
| MCP:dPjUR5 |     dependencies {
| MCP:dPjUR5 |         annotationProcessor 'org.springframework.boot:spring-boot-configuration-processor'
| MCP:dPjUR5 |         testImplementation 'org.springframework.boot:spring-boot-test'
| MCP:dPjUR5 |         testImplementation 'org.junit.jupiter:junit-jupiter-api'
| MCP:dPjUR5 |         testImplementation 'org.junit.jupiter:junit-jupiter-engine'
| MCP:dPjUR5 |         testRuntimeOnly 'org.junit.platform:junit-platform-launcher'
| MCP:dPjUR5 |         testImplementation 'org.assertj:assertj-core'
| MCP:dPjUR5 |         testImplementation 'org.mockito:mockito-core'
| MCP:dPjUR5 |     }
| MCP:dPjUR5 | 
| MCP:dPjUR5 |     java {
| MCP:dPjUR5 |         toolchain {
| MCP:dPjUR5 |             languageVersion = JavaLanguageVersion.of(project.javaVersion)
| MCP:dPjUR5 |         }
| MCP:dPjUR5 |     }
| MCP:dPjUR5 | 
| MCP:dPjUR5 |     bootJar.enabled = false
| MCP:dPjUR5 |     jar.enabled = true
| MCP:dPjUR5 | 
| MCP:dPjUR5 |     test {
| MCP:dPjUR5 |         useJUnitPlatform {
| MCP:dPjUR5 |             excludeTags 'develop', 'restdocs'
| MCP:dPjUR5 |         }
| MCP:dPjUR5 |     }
| MCP:dPjUR5 | 
| MCP:dPjUR5 |     testing {
| MCP:dPjUR5 |         suites {
| MCP:dPjUR5 |             test {
| MCP:dPjUR5 |                 targets {
| MCP:dPjUR5 |                     unitTest {
| MCP:dPjUR5 |                         testTask.configure {
| MCP:dPjUR5 |                             group = 'verification'
| MCP:dPjUR5 |                             useJUnitPlatform {
| MCP:dPjUR5 |                                 excludeTags 'develop', 'context', 'restdocs'
| MCP:dPjUR5 |                             }
| MCP:dPjUR5 |                         }
| MCP:dPjUR5 |                     }
| MCP:dPjUR5 | 
| MCP:dPjUR5 |                     contextTest {
| MCP:dPjUR5 |                         testTask.configure {
| MCP:dPjUR5 |                             group = 'verification'
| MCP:dPjUR5 |                             useJUnitPlatform {
| MCP:dPjUR5 |                                 includeTags 'context'
| MCP:dPjUR5 |                             }
| MCP:dPjUR5 |                         }
| MCP:dPjUR5 |                     }
| MCP:dPjUR5 | 
| MCP:dPjUR5 |                     restDocsTest {
| MCP:dPjUR5 |                         testTask.configure {
| MCP:dPjUR5 |                             group = 'verification'
| MCP:dPjUR5 |                             useJUnitPlatform {
| MCP:dPjUR5 |                                 includeTags 'restdocs'
| MCP:dPjUR5 |                             }
| MCP:dPjUR5 |                         }
| MCP:dPjUR5 |                     }
| MCP:dPjUR5 | 
| MCP:dPjUR5 |                     developTest {
| MCP:dPjUR5 |                         testTask.configure {
| MCP:dPjUR5 |                             group = 'verification'
| MCP:dPjUR5 |                             useJUnitPlatform {
| MCP:dPjUR5 |                                 includeTags 'develop'
| MCP:dPjUR5 |                             }
| MCP:dPjUR5 |                         }
| MCP:dPjUR5 |                     }
| MCP:dPjUR5 |                 }
| MCP:dPjUR5 |             }
| MCP:dPjUR5 |         }
| MCP:dPjUR5 |     }
| MCP:dPjUR5 | 
| MCP:dPjUR5 |     tasks.named('asciidoctor').configure {
| MCP:dPjUR5 |         dependsOn restDocsTest
| MCP:dPjUR5 |     }
| MCP:dPjUR5 | }
